section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/vui-conversation-design.json",
  "title": "VUI Conversation Design",
  "type": "object",
  "required": [
    "artefact_id",
    "intents",
    "slots",
    "prompt_classes",
    "happy_paths",
    "repair_branches",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "intents": {
      "type": "array",
      "description": "{name, slots, sample_utterances}",
      "minItems": 1
    },
    "slots": {
      "type": "array",
      "description": "{name, type, validation}",
      "minItems": 1
    },
    "prompt_classes": {
      "type": "object",
      "description": "open / directed / option / confirmation copy"
    },
    "happy_paths": {
      "type": "array",
      "description": "ordered turn-by-turn flows",
      "minItems": 1
    },
    "repair_branches": {
      "type": "object",
      "description": "no-match / no-input / max-retry / escape policies"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "vui-conversation-design-2026-05-23",
  "intents": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "slots": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "prompt_classes": {
    "key": "value"
  },
  "happy_paths": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "repair_branches": {
    "key": "value"
  },
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
